"""
mkt-christ layer — Titus chapters 1–3 (fills all missing verses)
Output: data/commentary/mkt-christ/titus.json
Run: python3 scripts/zc-christ-titus-1-3-full.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "1": {
    "1": "<p>Paul identifies himself as 'a servant (<em>doulos</em>) of God and apostle of Jesus Christ' — the double title is unusual; he normally calls himself servant of Christ Jesus (Rom 1:1; Phil 1:1). The addition of 'servant of God' connects his mission to the OT Mosaic tradition of the 'servant of God' (Moses, Josh 1:2; David, Ps 89:20; Isaiah's Servant). The Christological frame: Paul's servanthood of God is exercised through apostleship to Christ Jesus — the two are inseparable, because the God Paul serves is known through the Christ whose apostle Paul is.</p>",
    "2": "<p>'In the hope of eternal life, which God, who does not lie, promised before the ages began' — the pre-temporal promise of eternal life establishes the Christological ground: the life Christ brings (John 10:10: I came that they may have life and have it abundantly; 11:25: I am the resurrection and the life) is the fulfillment of an eternal divine commitment that preceded the world's creation. The incarnation is not God's response to the world's failure but the execution of a pre-temporal plan; Christ is the guaranteed content of what God promised before time.</p>",
    "3": "<p>'At his appointed season God brought it to light through the preaching entrusted to me' — the <em>epiphaneia</em> vocabulary (appearing, manifestation) is here expressed through 'brought to light' (<em>ephanerōsen</em>): the eternal promise became visible, disclosed, epiphanic in the Christ-event. Paul's preaching is the vehicle of this disclosure; Christ is both the content disclosed and the one through whom disclosure occurs. The 'command of God our Savior' that authorizes Paul's preaching is simultaneously the command of the God who appointed the time and the God who sent the Christ.</p>",
    "4": "<p>'To Titus, my true child in our common faith: Grace and peace from God the Father and Christ Jesus our Savior' — the 'common faith' (<em>koinēn pistin</em>) is the shared Christological confession that makes Paul and Titus spiritual family: faith in Christ Jesus who is 'our Savior.' The Savior title is applied to Christ here in a way that completes the parallel with v. 3's 'God our Savior' — both Father and Son bear the Savior title, and both are co-sources of the grace and peace that the greeting conveys.</p>",
    "5": "<p>'Put in order what remains and appoint elders in every town, as I directed' — the church-planting mission in Crete is Christological work: establishing the communities that gather in Christ's name and are ordered for his service. The 'appointing' of elders is an apostolic act in Christ's name; the communities they serve are communities of the Christ who is the head of the church (Eph 1:22-23). Titus functions as the on-site extension of Paul's apostolic mandate to establish Christ's community in every place.</p>",
    "6": "<p>'If anyone is above reproach, the husband of one wife, and his children are believers and not open to the charge of debauchery or insubordination' — the overseer's family integrity is Christomorphic: the 'husband of one wife' mirrors Christ's covenant faithfulness to the one church, his bride (Eph 5:25-27: Christ loved the church and gave himself up for her). The believing children of a believing household reflect the Christological reality that faith produces community; the household that models faith is the qualitative preview of the larger community the elder oversees.</p>",
    "7": "<p>'As God's steward (<em>oikonomos theou</em>), he must be above reproach' — the overseer is God's household manager; the household is God's through Christ's redemption (Acts 20:28: the church of God which he obtained with his own blood). Managing God's household is a Christological responsibility: the one who paid for the household with his blood has appointed the overseer as steward of what he purchased. The qualifications that follow (not arrogant, not quick-tempered, not a drunkard, not violent, not greedy) describe the character of the servant who represents the master faithfully.</p>",
    "8": "<p>'But hospitable, a lover of good, self-controlled, upright, holy, and disciplined' — the positive qualifications are Christomorphic character traits: hospitality mirrors Christ who welcomed sinners and tax collectors (Luke 15:1-2); love of good mirrors Christ who 'went about doing good' (Acts 10:38); self-control mirrors Christ's mastery of himself; holiness mirrors the one who was 'holy, innocent, unstained, separated from sinners' (Heb 7:26). The elder is to be a local embodiment of the character of the one in whose name he leads.</p>",
    "9": "<p>'He must hold firm to the trustworthy word as taught, so that he may be able to give instruction in sound doctrine and also to rebuke those who contradict it' — the 'trustworthy word' (<em>pistos logos</em>) is the apostolic proclamation of Christ; holding it firm is the doctrinal counterpart to the personal integrity just described. The capacity to teach sound doctrine and rebuke error is derivative from the word's own power: the overseer who holds the word firmly is given the word's own capacity to instruct and rebuke. The Christological content of the word is the source of its power.</p>",
    "10": "<p>'For there are many who are insubordinate, empty talkers and deceivers, especially those of the circumcision party' — the 'circumcision party' (<em>hoi ek tēs peritomēs</em>) represents the Judaizing tendency that Paul addressed in Galatia and elsewhere: the insistence on Torah observance as the ground of standing with God. The Christological error: they are substituting the Mosaic system (circumcision, Jewish genealogies, food laws) for the Christ who is the telos of the law (Rom 10:4). Their emptiness is Christological: they are full of words about everything except the one thing needful.</p>",
    "11": "<p>'They must be silenced, since they are upsetting whole households by teaching for shameful gain what they ought not to teach' — the false teachers' disruption of households is an assault on the Christ-community's foundational structure. The house-church, the Christian household, the widow enrolled in the church's care — all of these are destabilized by the false teaching. Silencing the disruptors is not censorship but the protection of Christ's community from the wolves that Paul warned of in Acts 20:29-30 (fierce wolves will come in, not sparing the flock).</p>",
    "12": "<p>'One of the Cretans, a prophet of their own, said, “Cretans are always liars, evil beasts, lazy gluttons”' — the citation of Epimenides (a Cretan philosopher) to diagnose Cretan character is an act of cultural wisdom analogous to Paul's use of Greek poets in Acts 17:28. The Christological relevance: the false teachers from the circumcision group (v. 10) have brought their errors into a cultural environment where the very people they seek to influence are characteristically susceptible to deception. Christ comes not to healthy cultures but to sick ones (Luke 5:31-32: those who are well have no need of a physician).</p>",
    "13": "<p>'This testimony is true. Therefore rebuke them sharply, that they may be sound in the faith' — the goal of the sharp rebuke (<em>apotomos</em>) is restoration to soundness in the faith: the medical metaphor of health (<em>hygiainō</em>) frames the rebuke not as punishment but as surgery. Christ the physician (Luke 5:31-32) is the model for the pastoral intervention Paul mandates: the harshness of the rebuke is proportional to the depth of the disease, and the goal is always the patient's health, not the physician's superiority.</p>",
    "14": "<p>'And not devoting themselves to Jewish myths and the commands of people who turn away from the truth' — the Jewish myths and human commands are Christologically displaced: they fill the space that Christ's word should occupy. The 'truth' (<em>alētheia</em>) from which the false teachers have turned away is ultimately the truth that is Christ himself (John 14:6: I am the way, the truth, and the life). Every turn from Christological truth is a turn toward some substitute — myth, tradition, speculative genealogy — that occupies the truth's place without its substance.</p>",
    "15": "<p>'To the pure, all things are pure, but to the defiled and unbelieving, nothing is pure; even their minds and consciences are defiled' — the Christological principle of purity: those who are in Christ are pure because Christ is their purification (1 Cor 1:30: he became to us wisdom from God, righteousness and sanctification and redemption). The defiled and unbelieving see everything through the lens of their unrenewed minds; they project their own defilement onto the world. The pure in Christ see creation through the lens of its Creator's goodness — the same lens Christ himself provided.</p>",
    "16": "<p>'They profess to know God, but they deny him by their works. They are detestable, disobedient, unfit for any good work' — the Christological test of knowledge: genuine knowledge of God produces the character that mirrors Christ; spurious knowledge produces only moral contradiction. Christ himself warned, 'Not everyone who says to me, Lord, Lord will enter the kingdom of heaven, but the one who does the will of my Father' (Matt 7:21). The false teachers' claim to know God is refuted by the same criterion: their works reveal the absence of the one they claim to know.</p>"
  },
  "2": {
    "1": "<p>'But as for you, teach what accords with sound doctrine' — the 'sound doctrine' (<em>hygiainousē didaskalia</em>) that Titus teaches is the Christological proclamation that the surrounding chapters specify: Christ's appearing (v. 11, 13), his self-giving redemption (v. 14), his justifying grace (3:7). Sound teaching is not primarily an intellectual standard but a Christological one: the doctrine is sound because it is oriented toward the healthy reality of Christ, who is both its content and its goal.</p>",
    "2": "<p>'Older men are to be sober-minded, dignified, self-controlled, sound in faith, in love, and in steadfastness' — the three graces (faith, love, steadfastness) that characterize the mature elder are the character of Christ reproduced in his disciple. Faith is the reception of Christ; love is the Christomorphic disposition of self-giving; steadfastness (<em>hypomonē</em>) is Christ's own patient endurance that believers are directed into (2 Thess 3:5). The aged believer's maturity is a Christological maturity: years of formation in Christ's pattern.</p>",
    "3": "<p>'Older women likewise are to be reverent in behavior, not slanderers or slaves to much wine, but teachers of what is good' — the older women's role as teachers-of-good to younger women is itself a Christological institution: the community shaped by Christ transmits his pattern through its most formed members. The 'reverent in behavior' (<em>hieroprepeis</em> — befitting what is holy) frames their entire demeanor as a form of worship, analogous to the priestly service of the tabernacle. Their teaching role is a ministry of Christ's character formation.</p>",
    "4": "<p>'Train the young women to love their husbands and children' — the domestic loves commanded here are Christologically grounded: the love of husband and children is a form of the self-giving love that Christ models (Eph 5:25: husbands, love your wives as Christ loved the church and gave himself up for her). The younger women who are trained to love their families embody the Christological love-ethic in the most intimate social contexts. The Titus household-code is not a social conservatism but a Christological formation program for the most proximate relationships.</p>",
    "5": "<p>'To be self-controlled, pure, working at home, kind, and submissive to their own husbands, that the word of God may not be reviled' — the final purpose clause — 'that the word of God may not be reviled' (<em>hina mē ho logos tou theou blasphēmētai</em>) — makes the household conduct of younger women a matter of Christological witness. The word of God they embody is ultimately Christ himself (John 1:1, 14: the Word became flesh). When their conduct is Christomorphic, it protects the credibility of the Christological proclamation they confess.</p>",
    "6": "<p>'Urge the younger men likewise to be self-controlled' — the single command to younger men — self-control — is the comprehensive virtue that encompasses all the rest. In the Platonic tradition, self-control (<em>sōphrosynē</em>) was the virtue that properly ordered the other virtues; in the Christological frame, it is the disposition that comes from being controlled not by one's own passions but by the Spirit of Christ (Gal 5:22-23: self-control is the final fruit of the Spirit). The younger man who is self-controlled has submitted his energy and drive to Christ's ordering.</p>",
    "7": "<p>'Show yourself in all respects to be a model of good works, and in your teaching show integrity, dignity' — Titus is to be the Christological prototype for the community: the <em>typos</em> (pattern) that Paul describes echoes the same word used of Paul himself as the prototype of grace in 1 Tim 1:16 (<em>hypotypōsis</em>). The modeling of good works is the Christological pedagogy: the teacher shows the life that Christ makes possible, not only argues for it. Integrity (<em>aphthorian</em>) in teaching is the Christological virtue of being uncorrupted — matching the incorruptible word with incorruptible character.</p>",
    "8": "<p>'And sound speech that cannot be condemned, so that an opponent may be put to shame, having nothing evil to say about us' — the sound speech (<em>logon hygiē</em>) that cannot be condemned is the Christologically shaped proclamation that matches the Christological life. Christ's own opponents were silenced when they could find no charge against him (Matt 22:46: no one was able to answer him a word); Titus's sound speech, grounded in the same truth, should produce the same silencing effect. The Christological integrity of word and life together is the apologetic.</p>",
    "9": "<p>'Bondservants are to be submissive to their own masters in everything; they are to be well-pleasing, not argumentative' — the instruction to enslaved persons has Christological grounding in the servant-pattern of Christ himself (Phil 2:7: he took on the form of a servant; Mark 10:45: the Son of Man came not to be served but to serve). The submission to masters is not an endorsement of the institution but an application of the Christological servant-pattern to the most constrained social location: even there, the Christ-pattern of faithful service is possible.</p>",
    "10": "<p>'Not stealing, but showing all good faith, so that in everything they may adorn the doctrine of God our Savior' — the 'adorning' of the doctrine (<em>kosmosin tēn didaskalian tēs tou theou sōtēros hēmōn</em>) is the Christological motivation for enslaved persons' faithful conduct: their trustworthiness makes the God who saved them visible and attractive. The doctrine of God our Savior is adorned not by theological argument but by the embodied character of those who have been saved by it. The enslaved person who models integrity is a Christological exhibit.</p>",
    "11": "<p>'For the grace of God has appeared (<em>epephanē</em>), bringing salvation to all people' — the appearing (<em>epiphaneia</em>) of grace is the Incarnation: grace is not an attribute of God abstractly considered but the person of Christ made visible in history. The grace that 'appeared' is Christ himself; the salvation it 'brings' is the salvation Christ accomplished. The universal scope ('to all people,' <em>pasin anthrōpois</em>) grounds all the preceding household-code instructions: the social transformation of household relationships is made possible by the universally-offered grace that appeared in Christ.</p>",
    "12": "<p>'Training us to renounce ungodliness and worldly passions, and to live self-controlled, upright, and godly lives in the present age' — the grace that appeared (Christ) functions pedagogically: it 'trains' (<em>paideuousa</em>) believers in the same way a master trains a pupil. Christ is not only the object of faith but the teacher of the new life that faith produces. The training in self-control, uprightness, and godliness is Christological formation: being shaped into the moral character that Christ embodies and the Spirit produces.</p>",
    "13": "<p>A direct revelation: 'Waiting for our blessed hope, the appearing of the glory of our great God and Savior Jesus Christ.' The syntax — 'our great God and Savior Jesus Christ' (<em>tou megalou theou kai sōtēros hēmōn Iēsou Christou</em>) — with a single definite article governing both nouns is one of the most explicit divine predications of Jesus in the entire NT (the Granville Sharp rule). Paul calls Jesus 'our great God' directly; the eschatological appearing of Christ is simultaneously the appearing of the glory of God himself. The Christological confession reaches its highest point in the letter here.</p>",
    "15": "<p>'Declare these things; exhort and rebuke with all authority. Let no one disregard you' — the authority Titus wields in declaring, exhorting, and rebuking is Christ's authority mediated through the apostolic commission. Christ gave the apostolic commission with 'all authority in heaven and on earth' (Matt 28:18-20); the minister who acts in Christ's name acts with that authority. The instruction 'let no one disregard you' parallels the instruction to Timothy about his youth (1 Tim 4:12) — the authority is not personal but Christological, and therefore not subject to social dismissal.</p>"
  },
  "3": {
    "1": "<p>'Remind them to be submissive to rulers and authorities, to be obedient, to be ready for every good work' — civic virtue as a Christological posture: Christ himself submitted to Roman authority (John 19:11: you would have no authority unless it were given you from above) and called his followers to render to Caesar what belongs to Caesar (Matt 22:21). The Christian's readiness for every good work in the civic sphere is an extension of Christ's own civic faithfulness and Paul's consistent instruction to pray for governing authorities (1 Tim 2:1-2).</p>",
    "2": "<p>'To speak evil of no one, to avoid quarreling, to be gentle, and to show perfect courtesy to all people' — the cluster of social virtues is Christomorphic: Christ who was reviled did not revile in return (1 Pet 2:23), who was gentle and lowly of heart (Matt 11:29), who showed courtesy to Samaritans, tax collectors, and sinners. The Titus community's gentle courtesy toward 'all people' — including non-Christians — is the public face of the Christological character that the grace of God (2:11-12) is producing in them.</p>",
    "3": "<p>'For we ourselves were once foolish, disobedient, led astray, slaves to various passions and pleasures, passing our days in malice and envy, hated by others and hating one another' — the 'we' is autobiographical and corporate: Paul and Titus and all Christians were once exactly what the Cretan false teachers and the unregenerate pagans are. The Christological implication: the grace that appeared in Christ (v. 4-7) can transform any person in any condition, because it transformed the ones writing the letter. The past condition of the letter's authors is the proof of the gospel's power.</p>",
    "5": "<p>A direct revelation: 'He saved us, not because of works done by us in righteousness, but according to his own mercy, by the washing of regeneration and renewing of the Holy Spirit, whom he poured out on us richly through Jesus Christ our Savior, so that being justified by his grace we might become heirs according to the hope of eternal life.' The Christological structure: salvation is mediated 'through Jesus Christ our Savior' — he is the channel through whom the Spirit is poured out and through whom justifying grace comes. The three acts (washing of regeneration, renewing of the Spirit, justification by grace) are all enacted through Christ.</p>",
    "6": "<p>'Whom he poured out on us richly through Jesus Christ our Savior' — the Spirit poured out (Pentecost: Acts 2:33: having received the promise of the Holy Spirit he has poured out this) comes through Christ. Christ is not only the content of the gospel but the mediator of the Spirit who applies it; the Trinitarian movement (Father saves, Spirit renews, Christ mediates) is fully present in a single verse. The richness of the pouring-out (<em>plousiōs</em>, generously, abundantly) reflects the superabundant grace Paul describes elsewhere as 'grace upon grace' (John 1:16) and 'overflowing' (Rom 5:15).</p>",
    "7": "<p>'So that being justified by his grace we might become heirs according to the hope of eternal life' — the justification that produces heirship is Christological at both ends: justified 'by his grace' is justified by the grace of Christ (Gal 2:21: I do not nullify the grace of God, for if righteousness were through the law, then Christ died for no purpose); the inheritance of eternal life is inheritance as 'fellow heirs with Christ' (Rom 8:17: and if children, then heirs — heirs of God and fellow heirs with Christ, provided we suffer with him). The heir-status is located in the relationship with Christ.</p>",
    "8": "<p>'The saying is trustworthy, and I want you to insist on these things, so that those who have believed in God may be careful to devote themselves to good works' — the fifth (or fourth, depending on counting) faithful saying formula endorses the preceding Christological-soteriological statement (vv. 4-7) as the reliable foundation for the ethical instruction that follows. The logical structure is Pauline: indicative (what God did in Christ) → imperative (therefore devote yourselves to good works). The good works are the Christological fruit of the Christological root.</p>",
    "9": "<p>'But avoid foolish controversies, genealogies, dissensions, and quarrels about the law, for they are unprofitable and worthless' — the controversies the false teachers generate are Christologically empty: they consume energy that should be directed toward Christ and produce nothing that resembles Christ's character. The 'quarrels about the law' (<em>machas nomikās</em>) are the same Jewish-speculative debates that Paul warned against in 1 Tim 1:4 and 6:4-5. The unprofitability (<em>anōpheleis</em>) of empty controversy stands in contrast to the profitability of Scripture that Paul commends to Timothy (2 Tim 3:16-17).</p>",
    "10": "<p>'As for a person who stirs up division (<em>hairetikon anthrōpon</em>), after warning him once and then twice, have nothing more to do with him' — the <em>hairetikos</em> (factious person, from <em>haireomai</em>, to choose) is one who chooses division over unity. The community discipline procedure — two warnings then separation — reflects Jesus's community discipline pattern in Matt 18:15-17 (go privately, then with witnesses, then to the church). The goal in Matt 18 is recovery; the limit (after two warnings) is the same. The Christological principle: the community constituted by Christ's reconciliation should pursue reconciliation exhaustingly before separation.</p>",
    "11": "<p>'Knowing that such a person is warped and sinful; he is self-condemned' — the self-condemnation of the divisive person is the eschatological echo of the final judgment: those who choose division against the Christ-community's unity condemn themselves by that choice. The Christological frame: the judgment seat of Christ (2 Cor 5:10) will ratify the self-condemnation that the divisive person has already pronounced. The community's separation is not the real judgment; it is the temporal form of the eschatological one that the person has already initiated.</p>",
    "12": "<p>'When I send Artemas or Tychicus to you, do your best to come to me at Nicopolis, for I have decided to spend the winter there' — the logistical planning of Paul's network is Christological work: the apostolic mission that moves people between Ephesus, Crete, Corinth, and Nicopolis is the organizational expression of the Christological mission to proclaim the appearing of God's grace (2:11) to all places. Paul's personal plans are always in service of the gospel whose content is Christ.</p>",
    "13": "<p>'Do your best to help Zenas the lawyer and Apollos on their way; see that they lack nothing' — Apollos (the eloquent Alexandrian teacher of Acts 18:24-28) appears here as a partner in the Cretan mission. His presence in the Pauline network — after his earlier association with the Corinthian church and his Alexandria-educated understanding of the Scriptures — shows the breadth of the apostolic coalition united around Christ. The provision for traveling missionaries is the community's material participation in the Christological mission.</p>",
    "14": "<p>'And let our people learn to devote themselves to good works, so as to help cases of urgent need, and not be unfruitful' — the fruitfulness expected of the Titus community is Christological fruitfulness: the vine-and-branches teaching of John 15 (I am the vine; whoever abides in me and I in him, he it is that bears much fruit) defines Christian fruitfulness as the natural product of union with Christ. The 'urgent needs' (<em>anagkaias chreias</em>) that the community meets by their good works are the concrete occasions where Christological love becomes visible action.</p>",
    "15": "<p>'Grace be with you all' — the final benediction is simultaneously the simplest and most comprehensive Christological statement: 'grace' is the shorthand for the entire Christ-event — the appearing of God's grace in Christ Jesus (2:11), the grace by which justification comes (3:7), the grace that is the source of all Paul's ministry (1:3). To pray that grace be with 'you all' is to pray that Christ himself, the embodied grace of God, be present with the whole community that bears his name.</p>"
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-christ', 'titus')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'titus', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'titus.json'))
    all_ok = True
    for ch in ['1', '2', '3']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ch, {}))} verses)')
    if all_ok:
        print('All verses present')
